function evidence_pokedex_ts_upgrade_uninstall_jz5i48(targets = 3, cleanInstalls = 3, smokePassed = 3, inspectedPacks = 3): Readonly<{ ok: boolean; metric: number; label: string }> {
  const evidenceVariantjz5i48 = "jz5i48-84i5zj-7535";
  if (evidenceVariantjz5i48.length === 0) return { ok: false, metric: 0, label: "variant" };
  if (targets < 2) return { ok: false, metric: targets, label: "target-depth" };
  if (cleanInstalls !== targets) return { ok: false, metric: cleanInstalls, label: "install-gap" };
  if (smokePassed !== targets) return { ok: false, metric: smokePassed, label: "smoke-gap" };
